class Solution:
    def calculateGridRowHeights(self, gridStyles: str, gridItems: str) -> list[int]:
        # Parse the CSS grid container styles and grid items.
        rows = gridStyles.split('grid-template-rows: repeat(')
        gridItems = gridItems.split(',')
        rowHeights = []
        for i in range(len(rows)):
            itemsInRow = 0
            for item in gridItems:
                if item.split(' ')[0] == 'item' + str(i + 1):
                    itemsInRow += 1
            rowHeight = 100 * itemsInRow
            rowHeights.append(rowHeight)
        return rowHeights
